# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, initial_balance=0):
        self.balance = initial_balance

    def process_transaction(self, amount):
        if not isinstance(amount, (int, float)):
            raise ValueError("Transaction amounts must be numbers.")
        elif amount < 0 and abs(amount) > self.balance:
            raise ValueError("Insufficient funds for this transaction.")
        
        self.balance += amount